import osimport pandas as pdimport scipy.signalfrom joblib import Parallel, delayedimport matplotlib# matplotlib.use('Agg')  # 加这个就不会崩溃import matplotlib.pyplot as pltimport numpy as npfrom tqdm import tqdmfrom astropy.timeseries import LombScarglefrom scipy.stats import linregress, normfrom scipy.optimize import curve_fitimport matplotlib.dates as mdatesfrom astropy.time import Timeplt.rcParams['font.sans-serif'] = ['SimHei']  # 使用黑体plt.rcParams['mathtext.fontset'] = 'stix'      # STIX字体支持数学符号plt.rcParams['font.family'] = 'STIXGeneral'plt.rcParams['axes.unicode_minus'] = Falsedef _clean_and_sort(series, flux, flux_err):    """    内部工具函数：清洗并同步排序时间、流量、误差。    """    series = np.asarray(series, dtype=float)    flux = np.asarray(flux, dtype=float)    flux_err = np.asarray(flux_err, dtype=float)    mask = np.isfinite(series) & np.isfinite(flux) & np.isfinite(flux_err) & (flux_err > 0)    series = series[mask]    flux = flux[mask]    flux_err = flux_err[mask]    idx = np.argsort(series)    return series[idx], flux[idx], flux_err[idx]def _weighted_intrinsic_std(y, dy):    """    估计红噪声内禀标准差：        intrinsic_var = total_var - measurement_noise_var    """    y = np.asarray(y, dtype=float)    dy = np.asarray(dy, dtype=float)    eps = np.finfo(float).eps    dy = np.maximum(dy, eps)    w = 1.0 / dy**2    mean_y = np.average(y, weights=w)    var_total = np.average((y - mean_y) ** 2, weights=w)    var_noise = np.average(dy ** 2, weights=w)    intrinsic_var = max(0.0, var_total - var_noise)    intrinsic_std = np.sqrt(intrinsic_var)    return intrinsic_std, mean_ydef _confidence_to_sigma(confidence):    """    将“显著性/置信度”转换为 sigma。    这里沿用你原来的写法：        sigma = norm.ppf(0.5 + confidence / 2)    """    if confidence is None or not np.isfinite(confidence):        return np.nan    confidence = float(np.clip(confidence, 0.0, 1.0))    if confidence >= 1.0:        confidence = 1.0 - 1e-12    return round(norm.ppf(0.5 + confidence / 2.0), 2)def _make_lomb_scargle(series, flux, flux_err=None, dy=None, periodogram_mode='lsp'):    """    根据 periodogram_mode 统一生成 LombScargle 对象：    - glsp: 考虑误差 dy    - lsp : 不考虑误差（普通 LSP）    兼容两种传参方式：    - flux_err=...    - dy=...    """    mode = str(periodogram_mode).lower()    # 兼容两种参数名    if flux_err is None and dy is not None:        flux_err = dy    if mode == 'glsp':        return LombScargle(            series, flux, dy=flux_err,            fit_mean=True, center_data=True,            normalization='standard'        )    elif mode == 'lsp':        return LombScargle(            series, flux,            fit_mean=False, center_data=True,            normalization='standard'        )    else:        raise ValueError("periodogram_mode 只能是 'glsp' 或 'lsp'")def _global_mc_confidence(all_sim_powers, peak_power):    """    用 Monte Carlo 的“整个频率范围最大功率”来计算全局显著性（global significance）。    定义为：        P(max(simulated power) < observed peak power)    """    if all_sim_powers is None:        return np.nan    arr = np.asarray(all_sim_powers, dtype=float)    if arr.size == 0:        return np.nan    if arr.ndim == 1:        arr = arr[np.newaxis, :]    sim_max = np.nanmax(arr, axis=1)    sim_max = sim_max[np.isfinite(sim_max)]    if sim_max.size == 0:        return np.nan    confidence = np.mean(sim_max < peak_power)    confidence = min(confidence, 1.0 - 1.0 / (sim_max.size + 1.0))    return confidencedef lsp_Method(series, flux, flux_err, divide_freq_step=10, periodogram_mode='lsp'):  # 主方法实现    """    Lomb-Scargle / Generalized Lomb-Scargle 周期图方法用于检测光变曲线中的周期性。    参数:    series: 时间序列，观测时间点。    flux: 流量序列，对应时间点的观测值。    flux_err: 观测误差。    divide_freq_step: 频率步长控制参数。    periodogram_mode: 'glsp' 或 'lsp'    返回:    frequency: 频率数组。    power: 功率谱。    """    # 同步排序，避免时间-流量错配    series, flux, flux_err = _clean_and_sort(series, flux, flux_err)    # 根据选择使用 GLSP / LSP    lsp = _make_lomb_scargle(        series, flux, flux_err=flux_err, periodogram_mode=periodogram_mode    )    # 频率范围    duration = series[-1] - series[0]    frequency_min = 1.0 / np.abs(duration)    N = len(series)    frequency_max = frequency_min * N / 2.0    delta_frequency = frequency_min / divide_freq_step    if frequency_max <= frequency_min:        frequency_max = frequency_min * 10.0    frequency = np.arange(frequency_min, frequency_max, delta_frequency)    if len(frequency) == 0:        frequency = np.array([frequency_min])    power = lsp.power(frequency)    return frequency, powerdef gen_TK95_noise(t, beta, target_std, mean_flux, leakage_factor=10):    """    Timmer & Koenig (1995) 风格的红噪声模拟。    注意：    - 这里生成长序列后随机截取，再插值到观测时间点，用于模拟 red-noise leakage    - 生成后再按 target_std 缩放，因此绝对归一化不敏感，但频谱形状要正确    """    t = np.asarray(t, dtype=float)    t = np.sort(t)    rng = np.random.default_rng()    N_orig = len(t)    duration = t[-1] - t[0]    if duration <= 0:        raise ValueError("时间序列跨度必须大于 0。")    T_long = duration * leakage_factor    # 保证 N_sim 足够大且是 2 的幂    N_sim = 2 ** int(np.ceil(np.log2(max(32, N_orig * leakage_factor * 2))))    # 正确的采样间隔    dt_long = T_long / N_sim    # 生成频率 (从 1/T_long 到 Nyquist)    freq = np.fft.rfftfreq(N_sim, d=dt_long)    freq[0] = freq[1]  # 避免除以 0    # 幅度谱 ~ f^(-beta/2)    power_law = freq ** (-beta / 2.0)    # 复高斯随机相位    real_part = rng.normal(0, 1, size=len(freq))    imag_part = rng.normal(0, 1, size=len(freq))    phases = (real_part + 1j * imag_part) / np.sqrt(2.0)    # 反变换得到长红噪声    time_series_long = np.fft.irfft(power_law * phases, n=N_sim)    t_sim_long = np.linspace(0, T_long, N_sim, endpoint=False)    # 随机截取并插值（模拟 leakage）    start_time = rng.uniform(0, T_long - duration)    sample_t = t - t[0] + start_time    resampled_flux = np.interp(sample_t, t_sim_long, time_series_long)    # 标准化到 target_std    std_now = np.std(resampled_flux)    if std_now <= 0 or not np.isfinite(std_now):        resampled_flux = np.zeros_like(resampled_flux)    else:        resampled_flux = (resampled_flux - np.mean(resampled_flux)) / std_now    return resampled_flux * target_std + mean_fluxdef calculate_binned_psd(freq, power, n_bins=12):    """    对功率谱进行对数分桶平滑 (Logarithmic Binning)    """    freq = np.asarray(freq, dtype=float)    power = np.asarray(power, dtype=float)    mask = np.isfinite(freq) & np.isfinite(power) & (freq > 0) & (power > 0)    freq = freq[mask]    power = power[mask]        if len(freq) == 0:        return np.array([]), np.array([])    if len(freq) < n_bins:        n_bins_actual = max(2, len(freq) // 2)    else:        n_bins_actual = n_bins    bins = np.logspace(np.log10(freq[0]), np.log10(freq[-1]), n_bins_actual + 1)    bin_centers = np.sqrt(bins[:-1] * bins[1:])    binned_power = []    for i in range(len(bins) - 1):        mask_bin = (freq >= bins[i]) & (freq < bins[i + 1])        if np.any(mask_bin):            binned_power.append(np.mean(power[mask_bin]))        else:            binned_power.append(np.nan)    return bin_centers, np.array(binned_power)def get_psd_slope(t, flux, flux_err, source_name, method='psresp',                  beta_range=np.arange(0.5, 2.5, 0.1),                  M=1000, n_bins=12, n_jobs=-1, plot=True,                  plot_mode='show', save_path='.',                  periodogram_mode='glsp'):    """    斜率估算函数    返回: beta_best, beta_error    新增:    periodogram_mode:        - 'glsp' : 考虑误差        - 'lsp'  : 不考虑误差    """    # 同步排序    t, flux, flux_err = _clean_and_sort(t, flux, flux_err)    mode = str(periodogram_mode).lower()    use_errors = (mode == 'glsp')    def _psresp_one_task(t, beta, mean_f, std_f, flux_err_array, freq_eval, n_bins, seed):        """        按照 PSRESP / Monte Carlo 要求进行模拟        """        rng = np.random.default_rng(int(seed))        # 1. 生成纯红噪声        sim_flux_red = gen_TK95_noise(t, beta, std_f, mean_f)        # 2. 是否加白噪声（GLSP 才加）        if use_errors:            poisson_noise = rng.normal(0, flux_err_array, size=len(t))            sim_flux_total = sim_flux_red + poisson_noise        else:            sim_flux_total = sim_flux_red        # 3. 计算周期图（GLSP 或 LSP）        ls = _make_lomb_scargle(            t, sim_flux_total, dy=flux_err_array, periodogram_mode=mode        )        p_sim = ls.power(freq_eval)        _, p_binned = calculate_binned_psd(freq_eval, p_sim, n_bins)        return p_binned    # 观测数据功率谱    f_min = 1.0 / (t[-1] - t[0])    # 经验 Nyquist    f_max = 0.5 / np.median(np.diff(t)) if len(t) > 2 else f_min * 50.0    freq_eval = np.linspace(f_min, f_max, 2000)    ls_obs = _make_lomb_scargle(t, flux, dy=flux_err, periodogram_mode=mode)    p_obs = ls_obs.power(freq_eval)    mean_f = np.nanmean(flux)    obs_std = np.nanstd(flux)    avg_err = np.nanmean(flux_err)    # 红噪声部分标准差    if use_errors:        intrinsic_std, _ = _weighted_intrinsic_std(flux, flux_err)        red_std_to_sim = intrinsic_std        if not np.isfinite(red_std_to_sim) or red_std_to_sim <= 0:            red_std_to_sim = np.sqrt(max(0.0, obs_std ** 2 - avg_err ** 2))    else:        red_std_to_sim = obs_std    if method.lower() == 'log':        # --- 方法一：改进的对数线性拟合 ---        bin_f, bin_p = calculate_binned_psd(freq_eval, p_obs, n_bins=n_bins)        valid = np.isfinite(bin_f) & np.isfinite(bin_p) & (bin_f > 0) & (bin_p > 0)        bin_f = bin_f[valid]        bin_p = bin_p[valid]        if len(bin_f) < 3:            raise RuntimeError("可用于对数拟合的数据点太少。")        # 只拟合前 80% 的频率，避开高频噪声        idx = max(3, int(len(bin_f) * 0.8))        idx = min(idx, len(bin_f))        res = linregress(np.log10(bin_f[:idx]), np.log10(bin_p[:idx]))        beta_best, beta_err = -res.slope, abs(res.stderr) if np.isfinite(res.stderr) else 0.2        if plot:            plt.figure(figsize=(7, 5))            raw_label = 'Raw GLSP' if mode == 'glsp' else 'Raw LSP'            plt.loglog(freq_eval, p_obs, color='gray', alpha=0.3, label=raw_label)            plt.loglog(bin_f, bin_p, 'ko', label='Binned Data', markersize=4)            f_fit = bin_f[:idx]            x_log = np.log10(f_fit)            y_log_fit = res.intercept + res.slope * x_log            int_stderr = getattr(res, 'intercept_stderr', 0.0)            if not np.isfinite(int_stderr):                int_stderr = 0.0            y_log_err = np.sqrt(int_stderr ** 2 + (x_log * res.stderr) ** 2)            y_log_upper = y_log_fit + y_log_err            y_log_lower = y_log_fit - y_log_err            plt.loglog(f_fit, 10 ** y_log_fit, 'r-', lw=2,                       label=f'Fit ($\\beta$={beta_best:.2f}$\\pm${beta_err:.2f})')            plt.fill_between(f_fit, 10 ** y_log_lower, 10 ** y_log_upper,                             color='red', alpha=0.2, label=r'1-$\sigma$ Uncertainty')            plt.xlabel('Frequency')            plt.ylabel('Power')            plt.title(f'Log-Linear Power Law Fit ({mode.upper()})')            plt.legend()            plt.grid(True, which="both", ls="-", alpha=0.1)            if plot_mode == "show":                plt.show()            if plot_mode == "save":                out_file = os.path.join(save_path, f'{source_name}_Log_linear.png')                plt.savefig(out_file, dpi=300)                plt.close()    elif method.lower() == 'psresp':        # --- 方法二：PSRESP 拟合 ---        bin_f, p_obs_binned = calculate_binned_psd(freq_eval, p_obs, n_bins=n_bins)                valid_obs = np.isfinite(bin_f) & np.isfinite(p_obs_binned) & (bin_f > 0) & (p_obs_binned > 0)        bin_f_valid = bin_f[valid_obs]        p_obs_binned_valid = p_obs_binned[valid_obs]        if len(bin_f_valid) < 3:            print(f"警告：PSRESP 可用分箱数据太少（{len(bin_f_valid)} 个点）。")            print(f"  - 原始频率点数: {len(freq_eval)}")            print(f"  - 分箱后总点数: {len(bin_f)}")            print(f"  - 有效点数: {len(bin_f_valid)}")            print(f"  - 频率范围: [{np.nanmin(freq_eval):.2e}, {np.nanmax(freq_eval):.2e}]")            print(f"  - 功率范围: [{np.nanmin(p_obs):.2e}, {np.nanmax(p_obs):.2e}]")            print("尝试切换到 'log' 方法...")                        beta_best, beta_err = get_psd_slope(                t, flux, flux_err, source_name,                method='log',                M=M,                n_bins=n_bins,                n_jobs=n_jobs,                plot=plot,                plot_mode=plot_mode,                save_path=save_path,                periodogram_mode=periodogram_mode            )            return beta_best, beta_err        success_fractions = []        # 预生成随机种子，避免并行随机数重复        rng_master = np.random.default_rng(42)        seeds = rng_master.integers(0, 2**32 - 1, size=M, dtype=np.uint32)        for beta in tqdm(beta_range, desc=f"Running PSRESP ({mode.upper()}, M={M})"):            results = Parallel(n_jobs=n_jobs)(                delayed(_psresp_one_task)(t, beta, mean_f, red_std_to_sim, flux_err, freq_eval, n_bins, seed)                for seed in seeds            )            sim_psds = np.array(results)            # 仅保留有效 bin            sim_psds = sim_psds[:, valid_obs]            p_sim_avg = np.nanmean(sim_psds, axis=0)            p_sim_std = np.nanstd(sim_psds, axis=0)            p_sim_std[~np.isfinite(p_sim_std) | (p_sim_std == 0)] = 1e-10            chi2_obs = np.sum(((p_obs_binned_valid - p_sim_avg) ** 2) / p_sim_std ** 2)            chi2_sims = np.sum(((sim_psds - p_sim_avg) ** 2) / p_sim_std ** 2, axis=1)            success_fractions.append(np.sum(chi2_sims > chi2_obs) / M)        sfs = np.array(success_fractions)        def gauss(x, A, mu, sigma, base):            return A * np.exp(-(x - mu) ** 2 / (2 * sigma ** 2)) + base        p0 = [np.max(sfs) - np.min(sfs), beta_range[np.nanargmax(sfs)], 0.3, np.min(sfs)]        try:            popt, _ = curve_fit(                gauss, beta_range, sfs, p0=p0,                bounds=([0, 0.5, 0.05, 0], [2, 3.0, 1.0, 1]),                maxfev=10000            )            beta_best, beta_err = popt[1], abs(popt[2])        except Exception:            print("Gaussian fit failed, using argmax.")            beta_best, beta_err = beta_range[np.nanargmax(sfs)], 0.2            popt = None        if plot:            plt.figure(figsize=(7, 5))            plt.plot(beta_range, success_fractions, 'bo', label='Success Fraction')            x_range = np.linspace(beta_range[0], beta_range[-1], 100)            if popt is not None:                plt.plot(x_range, gauss(x_range, *popt), 'r-',                         label=f'Best Beta: {beta_best:.2f} ± {beta_err:.2f}')            plt.xlabel("Beta")            plt.ylabel("SF")            plt.legend()            plt.title(f"PSRESP Success Fraction Curve ({mode.upper()})")            if plot_mode == "show":                plt.show()            if plot_mode == "save":                out_file = os.path.join(save_path, f'{source_name}_PSRESP.png')                plt.savefig(out_file, dpi=300)                plt.close()    else:        raise ValueError("method 只能是 'psresp' 或 'log'")    return beta_best, beta_errdef calculate_Lsp_FAP(series, flux, flux_err, beta_best, frequency, M=10000, n_jobs=10,                      periodogram_mode='lsp'):    # 蒙特卡洛模拟    # 1. 并行生成大量背景噪声功率谱    # 同步排序，避免错配    series, flux, flux_err = _clean_and_sort(series, flux, flux_err)    mode = str(periodogram_mode).lower()    use_errors = (mode == 'glsp')    mean_f = np.nanmean(flux)    obs_std = np.nanstd(flux)    avg_err = np.nanmean(flux_err)    if use_errors:        intrinsic_std, _ = _weighted_intrinsic_std(flux, flux_err)        red_std = intrinsic_std        if not np.isfinite(red_std) or red_std <= 0:            red_std = np.sqrt(max(0.0, obs_std ** 2 - avg_err ** 2))    else:        red_std = obs_std    rng_master = np.random.default_rng(123456)    seeds = rng_master.integers(0, 2**32 - 1, size=M, dtype=np.uint32)    def run_one_sim(seed):        rng = np.random.default_rng(int(seed))        # 生成红噪声        s_flux = gen_TK95_noise(series, beta_best, red_std, mean_f)        # 是否加入白噪声（GLSP 才加）        if use_errors:            s_flux += rng.normal(0, flux_err, size=len(series))        # 计算周期图（GLSP 或 LSP）        ls = _make_lomb_scargle(            series, s_flux, dy=flux_err, periodogram_mode=mode        )        return ls.power(frequency)    all_powers = Parallel(n_jobs=n_jobs)(        delayed(run_one_sim)(seed) for seed in tqdm(seeds, desc=f"Generating {M} background realizations ({mode.upper()})")    )    all_powers_np = np.array(all_powers)  # Shape: (n_sim, len(freq_eval))    # 如果你后续想画阈值线，可以直接在 plot_LSP 里对 all_powers_np 求百分位    return all_powers_npdef get_LSP_periods(freq, power_obs, all_sim_powers,                    min_period=1.0,      # 过滤掉小于1天的所有“噪音周期”                    sig_threshold=0.997, # 3-sigma 门槛（局部显著性）                    top_n=3,             # 只显示置信度最高的前N个结果                    global_sig_threshold=None):  # 可选：全局显著性门槛    # 1. 在观测功率谱中寻找峰值    peaks, properties = scipy.signal.find_peaks(power_obs, distance=20, prominence=0.01)    results = []    all_sim_powers_np = None    global_sim_max = None    if all_sim_powers is not None:        all_sim_powers_np = np.asarray(all_sim_powers, dtype=float)        if all_sim_powers_np.ndim == 1:            all_sim_powers_np = all_sim_powers_np[np.newaxis, :]        global_sim_max = np.nanmax(all_sim_powers_np, axis=1)        global_sim_max = global_sim_max[np.isfinite(global_sim_max)]    for p_idx in peaks:        f_peak = freq[p_idx]        p_peak = power_obs[p_idx]        period = 1.0 / f_peak        # A. 周期过滤：排除过短周期        if period < min_period:            continue        # B. 局部显著性计算（在该频点上的模拟分布）        if all_sim_powers_np is not None:            sim_distribution = all_sim_powers_np[:, p_idx]            sim_distribution = sim_distribution[np.isfinite(sim_distribution)]            if len(sim_distribution) == 0:                significance = np.nan            else:                # 这里定义为“置信度”：                # 多少比例的模拟值低于观测值                significance = np.mean(sim_distribution < p_peak)                # 防止极端情况下数值上界略超                significance = min(significance, 1 - 1 / (len(sim_distribution) + 1))        else:            significance = np.nan        # C. 全局显著性计算（考虑整个频率范围）        if global_sim_max is not None and len(global_sim_max) > 0:            global_significance = np.mean(global_sim_max < p_peak)            global_significance = min(global_significance, 1 - 1 / (len(global_sim_max) + 1))        else:            global_significance = np.nan        # D. 门槛过滤        if np.isfinite(significance) and significance < sig_threshold:            continue        if global_sig_threshold is not None:            if (not np.isfinite(global_significance)) or (global_significance < global_sig_threshold):                continue        p_val, p_err = get_period_error(freq, power_obs, f_peak)        sigma_val = _confidence_to_sigma(significance)        global_sigma_val = _confidence_to_sigma(global_significance)        results.append({            'frequency': f_peak,            'period_org': round(period, 2),            'power': p_peak,            'significance': significance,               # 保留原来的 key：局部显著性            'global_significance': global_significance, # 新增：全局显著性            'period': p_val,            'period_err': p_err,            'sigma': sigma_val,            'global_sigma': global_sigma_val        })    # 只取置信度最高的 Top N    def _sort_key(x):        sig = x.get('significance', np.nan)        sig_key = sig if np.isfinite(sig) else 0.0        return (sig_key, x.get('power', -np.inf))    results = sorted(results, key=_sort_key, reverse=True)[:top_n]    return resultsdef get_period_error(freq, power, f_peak):    """    通过对峰值周围进行高斯拟合来估算频率和周期的误差    """    freq = np.asarray(freq, dtype=float)    power = np.asarray(power, dtype=float)    # 1. 截取峰值周围的数据点 (例如取峰值频率的 +/- 10% 范围)    mask = (freq > f_peak * 0.9) & (freq < f_peak * 1.1)    f_sub = freq[mask]    p_sub = power[mask]    # 过滤无效值    valid = np.isfinite(f_sub) & np.isfinite(p_sub)    f_sub = f_sub[valid]    p_sub = p_sub[valid]    if len(f_sub) < 5:        return 1.0 / f_peak, (1.0 / f_peak) ** 2 * (freq[1] - freq[0]) if len(freq) > 1 else np.nan    # 2. 定义高斯函数    def gaussian(x, a, mu, sigma):        return a * np.exp(-(x - mu) ** 2 / (2 * sigma ** 2))    try:        p0 = [np.max(p_sub), f_peak, max((f_sub[-1] - f_sub[0]) / 4, np.median(np.diff(f_sub)))]        popt, _ = curve_fit(gaussian, f_sub, p_sub, p0=p0, maxfev=10000)        a_fit, f_fit, f_sigma = popt        # 3. 计算周期和周期误差        best_period = 1.0 / f_fit        period_error = abs(f_sigma) / (f_fit ** 2)        return best_period, period_error    except Exception:        return 1.0 / f_peak, (1.0 / f_peak) ** 2 * (freq[1] - freq[0]) if len(freq) > 1 else np.nandef plot_LSP(source_name, freq, power, sig, detected_signals, series, flux, flux_err,             plot_mode="save", save_path=".",             time_axis_mode="ym",   # "ym" = 年月, "jd" = JD             time_input_format="jd", # 如果 series 是 MJD，就改成 "mjd"             periodogram_mode='lsp'):    """    绘制 Lomb-Scargle Periodogram（上图）和光变曲线（下图）。    新增：    - 显示局部显著性阈值    - 显示全局显著性阈值（基于每次 Monte Carlo 的最大功率）    - 在检测峰值上同时标注 Local / Global significance    """    # -----------------------------    # 转为 numpy 数组    # -----------------------------    freq = np.asarray(freq, dtype=float)    power = np.asarray(power, dtype=float)    sig = np.asarray(sig, dtype=float) if sig is not None else None    series = np.asarray(series, dtype=float)    flux = np.asarray(flux, dtype=float)    flux_err = np.asarray(flux_err, dtype=float)    if time_axis_mode not in ("ym", "jd"):        raise ValueError("time_axis_mode must be 'ym' or 'jd'")    # -----------------------------    # 建图    # -----------------------------    fig, (ax1, ax2) = plt.subplots(2, 1, figsize=(13, 6))    # ============================================================    # 图 1：LSP / GLSP    # ============================================================    ax1.plot(freq, power, 'k-', alpha=0.8, label='Power')    # 局部阈值 + 全局阈值    if sig is not None:        sig_95 = np.percentile(sig, 95, axis=0)        sig_99 = np.percentile(sig, 99.7, axis=0)        ax1.plot(freq, sig_95, 'g--', label='95% (2σ) Local Threshold', lw=1)        ax1.plot(freq, sig_99, 'r--', label='99.7% (3σ) Local Threshold', lw=1.5)        # # 全局阈值：每次模拟取最大功率，再做 percentile        # sim_max = np.nanmax(sig, axis=1)        # sim_max = sim_max[np.isfinite(sim_max)]        # if len(sim_max) > 0:        #     global_95 = np.percentile(sim_max, 95)        #     global_99 = np.percentile(sim_max, 99.7)        #        #     ax1.axhline(global_95, color='dodgerblue', linestyle='-.', lw=1.1,        #                 label='95% Global Threshold')        #     ax1.axhline(global_99, color='navy', linestyle='-.', lw=1.6,        #                 label='99.7% Global Threshold')    if detected_signals:        for i, s in enumerate(detected_signals):            p_val = s['period']            p_err = s['period_err']            f0 = s['frequency']            pwr = s.get('power', np.nan)            local_sig = s.get('significance', np.nan)            global_sig = s.get('global_significance', np.nan)            local_sigma = s.get('sigma', np.nan)            global_sigma = s.get('global_sigma', np.nan)            # 防止 period - err <= 0            denom_low = max(p_val - p_err, np.finfo(float).eps)            f_low = 1.0 / (p_val + p_err)            f_high = 1.0 / denom_low            label_parts = [f"P = {p_val:.2f} ± {p_err:.2f} d"]            if np.isfinite(local_sig):                label_parts.append(f"Local = {local_sig * 100:.2f}% ({local_sigma}σ)")            if np.isfinite(global_sig):                label_parts.append(f"Global = {global_sig * 100:.2f}% ({global_sigma}σ)")            label_text = "\n".join(label_parts)            ax1.axvline(                x=f0,                color='darkorange',                linestyle='--',                lw=1.5,                alpha=0.7,                label='Detected Signal' if i == 0 else None            )            ax1.axvspan(                f_low, f_high,                alpha=0.2,                color='orange',                label='Error Range' if i == 0 else None            )            y_text = pwr * 0.65 if np.isfinite(pwr) else np.nanmax(power) * 0.65            ax1.text(                f0 * 1.1, y_text, label_text,                fontsize=11,                fontweight='bold',                color='darkred'            )    ax1.set_xscale('log')    ax1.set_xlabel("Frequency (1/day)")    ax1.set_ylabel("Power")    ax1.set_title(f'{source_name} Lomb-Scargle Periodogram') if periodogram_mode == 'lsp' else ax1.set_title(f'{source_name} Generalized Lomb-Scargle Periodogram')    ax1.grid(True, which="both", ls="-", alpha=0.12)    # 去重 legend    handles1, labels1 = ax1.get_legend_handles_labels()    by_label1 = dict(zip(labels1, handles1))    ax1.legend(by_label1.values(), by_label1.keys(), loc='best')    # ============================================================    # 图 2：光变曲线    # ============================================================    if time_axis_mode == "ym":        series_plot = Time(series, format=time_input_format).to_datetime()        x_label = "Year-Month"    else:        series_plot = series        x_label = "JD"    ax2.errorbar(        series_plot, flux, yerr=flux_err,        color='darkcyan',        fmt='.',        alpha=0.4,        label='Observed Data'    )    ax2.set_ylabel('Flux')    ax2.set_xlabel(x_label)    ax2.grid(True, linestyle='--', alpha=0.7)    def fit(jd_series, flux, detected_frequencies):        """        利用线性最小二乘法拟合：            y = offset + Σ [a_i cos(2π f_i t) + b_i sin(2π f_i t)]        """        t = np.asarray(jd_series, dtype=float)        y = np.asarray(flux, dtype=float)        # 设计矩阵        A_matrix = [np.ones_like(t)]        for f in detected_frequencies:            A_matrix.append(np.cos(2 * np.pi * f * t))            A_matrix.append(np.sin(2 * np.pi * f * t))        A_matrix = np.array(A_matrix).T        # 最小二乘        coeffs, _, _, _ = np.linalg.lstsq(A_matrix, y, rcond=None)        # 平滑时间轴        t_smooth = np.linspace(t.min(), t.max(), 2000)        # 拟合曲线        final_fit = np.full_like(t_smooth, coeffs[0], dtype=float)        component_params = []        for i, f in enumerate(detected_frequencies):            a = coeffs[2 * i + 1]            b = coeffs[2 * i + 2]            amp = np.sqrt(a ** 2 + b ** 2)            phase = np.arctan2(a, b)            # 不再人为乘 1.5，保持真实拟合            final_fit += amp * np.sin(2 * np.pi * f * t_smooth + phase)            component_params.append({'f': f, 'amp': amp, 'phase': phase})        return t_smooth, final_fit, component_params, coeffs[0]    if detected_signals:        best_signal = max(            detected_signals,            key=lambda x: x.get('sigma', -np.inf) if np.isfinite(x.get('sigma', np.nan)) else -np.inf        )        detected_frequencies = [best_signal['frequency']]        t_plot, y_plot, params, final_offset = fit(series, flux, detected_frequencies)        if time_axis_mode == "ym":            t_plot_plot = Time(t_plot, format=time_input_format).to_datetime()        else:            t_plot_plot = t_plot        ax2.plot(            t_plot_plot, y_plot,            'r--',            lw=2,            label=f"P = {best_signal['period']:.2f} d",            zorder=3        )    if time_axis_mode == "ym":        ax2.xaxis.set_major_locator(mdates.AutoDateLocator())        ax2.xaxis.set_major_formatter(mdates.DateFormatter('%Y-%m'))        fig.autofmt_xdate()    # 去重 legend    handles2, labels2 = ax2.get_legend_handles_labels()    by_label2 = dict(zip(labels2, handles2))    ax2.legend(by_label2.values(), by_label2.keys(), loc='best')    plt.tight_layout()    # -----------------------------    # 显示 / 保存    # -----------------------------    if plot_mode == "show":        plt.show()    elif plot_mode == "save":        os.makedirs(save_path, exist_ok=True)        out_file = os.path.join(save_path, f'{source_name}_LSP.png') if periodogram_mode == 'lsp' else os.path.join(save_path, f'{source_name}_GLSP.png')        plt.savefig(out_file, dpi=300, bbox_inches='tight')        plt.close(fig)        print(f"{source_name} - LSP 绘图完成，保存在 {out_file}")    return fig, (ax1, ax2)# --- 主运行流程 ---if __name__ == "__main__":    file_map = r"S:\FermiData\fsrq\weekly\124_4FGL_J0457.0-2324_weekly_2024_8_9.csv"    try:        df = pd.read_csv(file_map, header=0, na_values='-')    except pd.errors.EmptyDataError:        df = pd.DataFrame()        print(f"文件 {file_map} 为空，已跳过！")    if df.empty:        raise RuntimeError(f"文件 {file_map} 为空或无法读取。")    # 根据数据类型处理CSV文件中的数据    # 统一用字符串检查 "<"    flux_col_str = df.iloc[:, 4].astype(str)    condition = ~flux_col_str.str.contains('<', na=False)    filtered_df = df[condition].copy()    # 从csv中提取数据列    julian_dates_o = pd.to_numeric(filtered_df.iloc[:, 1], errors='coerce').values    photon_fluxes_o = pd.to_numeric(filtered_df.iloc[:, 4], errors='coerce').values    photon_fluxes_err = pd.to_numeric(filtered_df.iloc[:, 5], errors='coerce').values    # 提取源名称 以'_'来分隔，若原数据不同，则可能会出现问题    filename = os.path.basename(file_map)    source_name = filename.split("_")[0] + "_" + filename.split("_")[1] + "_" + filename.split("_")[2]    # 去掉错误数据如nan，并同步排序    mask = np.isfinite(julian_dates_o) & np.isfinite(photon_fluxes_o) & np.isfinite(photon_fluxes_err) & (photon_fluxes_err > 0)    t = julian_dates_o[mask]    flux = photon_fluxes_o[mask]    flux_err = photon_fluxes_err[mask]    idx = np.argsort(t)    t = t[idx]    flux = flux[idx]    flux_err = flux_err[idx]    # ==========================================    # 统一设置：全局选用 glsp / lsp    # glsp = 考虑误差    # lsp  = 不考虑误差    # ==========================================    periodogram_mode = "lsp"   # 改成 "lsp" 就是普通 LSP    # ==========================================    # 3. 计算 LSP 谱与置信度 (LSP & Confidence Levels)    # ==========================================    print(f"正在计算 {periodogram_mode.upper()} 功率谱及蒙特卡洛置信度...")    # 获取频率范围    freq, power = lsp_Method(t, flux, flux_err, periodogram_mode=periodogram_mode)    MC = True    # 计算基于当前 beta 的置信线    if MC:        # ==========================================        # 2. 估计 PSD 斜率 beta (Beta Estimation)        # ==========================================        print(f"正在估算 PSD 斜率 beta（{periodogram_mode.upper()}）...")        # 使用 PSRESP 方法        beta_best, beta_err = get_psd_slope(            t, flux, flux_err, 't',            method='psresp',            beta_range=np.arange(0.1, 2.1, 0.1),            M=1000,            n_jobs=-1,            plot=True,            n_bins=6,            plot_mode="show",            periodogram_mode=periodogram_mode        )        print(f"拟合得到的最佳 beta: {beta_best:.2f} ± {beta_err:.2f}")        sig = calculate_Lsp_FAP(            t, flux, flux_err,            beta_best=beta_best,            frequency=freq,            M=10000,  # 模拟次数            n_jobs=-1,            periodogram_mode=periodogram_mode        )    else:        sig = None    detected_signals = get_LSP_periods(freq, power, sig)    print("\n--- 自动检测结果 ---")    if not detected_signals:        print("没有发现超过阈值的周期信号。")    else:        for s in detected_signals:            msg = (                f"检测到信号！ 周期: {s['period']:.2f} ± {s['period_err']:.2f} 天, "                f"局部置信度: {s['significance'] * 100:.2f}%"            )            if np.isfinite(s.get('global_significance', np.nan)):                msg += f", 全局置信度: {s['global_significance'] * 100:.2f}%"            print(msg)    plot_LSP(        source_name,        freq, power, sig, detected_signals,        t, flux, flux_err,        plot_mode='show',        time_axis_mode='ym',        periodogram_mode = periodogram_mode    )